"""
MCP Calculator Tools Server

This module contains the FastMCP server with calculator tools.
"""

import os

from awslabs.mcp_lambda_handler import MCPLambdaHandler

# Get session table name from environment variable
session_table = os.environ.get("MCP_SESSION_TABLE", "mcp_sessions")

# Create the MCP server instance
mcp_server = MCPLambdaHandler(name="mcp-lambda-server", version="1.0.0", session_store=session_table)


@mcp_server.tool()
def add(a: float, b: float) -> float:
    """Add two numbers."""
    return a + b


@mcp_server.tool()
def subtract(a: float, b: float) -> float:
    """Subtract two numbers."""
    return a - b


@mcp_server.tool()
def multiply(a: float, b: float) -> float:
    """Multiply two numbers."""
    return a * b


@mcp_server.tool()
def divide(a: float, b: float) -> float:
    """Divide two numbers."""
    if b == 0:
        raise ValueError("Division by zero")
    return a / b


def lambda_handler(event, context):  # noqa: ANN001, ANN201
    """AWS Lambda handler function."""
    return mcp_server.handle_request(event, context)
